// Prepare sync log entry
const input = $input.first().json;
const syncEndTime = new Date();
const syncStartTime = new Date(input.sync_start_time);
const durationSeconds = Math.floor((syncEndTime - syncStartTime) / 1000);

// Determine sync status
let status = 'success';
if (input.errors && input.errors.length > 0) {
  status = input.products_added > 0 || input.products_updated > 0 ? 'partial' : 'failed';
}

// Calculate cost estimate for Tier 3
let costEstimate = 0;
if (input.tier_used === 3) {
  const zyteRequests = input.products_added + input.products_updated;
  const zyteCost = zyteRequests * 0.00013;
  const geminiCost = zyteRequests * 0.002;
  costEstimate = zyteCost + geminiCost;
}

const logEntry = {
  sync_date: syncEndTime.toISOString(),
  vendor_id: input.vendor_id,
  vendor_name: input.vendor_name,
  status: status,
  products_updated: input.products_updated || 0,
  products_added: input.products_added || 0,
  products_skipped: input.products_skipped || 0,
  errors: input.errors || [],
  duration_seconds: durationSeconds,
  tier_used: input.tier_used,
  cost_estimate: costEstimate,
  new_markettime_items: input.new_markettime_items || 0
};

return [{ json: logEntry }];

// Return the log entry with sync status for downstream processing
const logEntry = $input.first().json;

return [{
  json: {
    ...logEntry,
    sync_status: logEntry.status,
    log_id: logEntry.id || logEntry.log_id
  }
}];
